import React from 'react';
import Icon from '@material-ui/core/Icon';
import email from '@material-ui/icons/Email';
import location_on from '@material-ui/icons/LocationOn';
import List from '@material-ui/core/List';
import ListItem from '@material-ui/core/ListItem';
import ListItemText from '@material-ui/core/ListItemText';
import ListItemIcon from '@material-ui/core/ListItemIcon';
import Avatar from '@material-ui/core/Avatar';
import GithubImg from '../images/GithubImage.png';
import { withStyles } from '@material-ui/core/styles';

const styles = {
listItemStyle: {
  width: 'auto',
  height: 'auto',
},
avatarStyle: {
  width: '1.25em',
  height: '1.25em',
},
};

class Contact extends React.Component {
  render() {
    return (
      <List>
        <ListItem>
          <ListItemIcon>
              <Icon>email</Icon>
          </ListItemIcon>
          <ListItemText primary="munnangi.prasanna@gmail.com" />
        </ListItem>

        <ListItem>
          <ListItemIcon>
              <Icon>location_on</Icon>
          </ListItemIcon>
          <ListItemText primary="Gainesville, FL" />
        </ListItem>
        <ListItem >
          <ListItemIcon classes={{width: 25, height: 25 }} >
            <Avatar src={GithubImg} sizes={{ width: 25,
            height: 25 }}>
            </Avatar>
          </ListItemIcon>
          <a target="_blank" rel="noopener noreferrer"  href="https://github.com/munnangi">
             <ListItemText primary="https://github.com/munnangi" />
          </a>

        </ListItem>
      </List>
    );
  }
}

export default withStyles(styles)(Contact);



